// 解析统一消息 Schema 的回调
const input = $input.first().json;
const taskId = input.task_id || 'unknown';
const status = input.status || 'completed';
const result = input.result || input.data || {};
const component = input.component || 'unknown';
const error = input.error || null;
const duration = input.duration_ms || 0;

// 按组件路由到不同的处理分支
let route = 'default';
if (component === 'langchain') route = 'langchain_result';
else if (component === 'claude_code') route = 'claude_result';
else if (component === 'openclaw') route = 'openclaw_result';
else if (status === 'failed') route = 'error_handler';

return {
  task_id: taskId,
  status: status,
  route: route,
  component: component,
  result: result,
  error: error,
  duration_ms: duration,
  processed_at: new Date().toISOString()
};

// LangChain 结果处理: 评测 + 规整
const data = $input.first().json;
const result = data.result || {};

// 对 AI 生成内容做质量评测
let quality_score = 0;
if (result.result && typeof result.result === 'string') {
  quality_score = result.result.length > 100 ? 7 : 5;
}

return {
  task_id: data.task_id,
  status: data.status,
  component: data.component,
  quality_score: quality_score,
  result: result,
  needs_retry: quality_score < 6,
  processed_at: data.processed_at
};

// Claude Code 结果处理: 审计通过性检查
const data = $input.first().json;
const result = data.result || {};

return {
  task_id: data.task_id,
  status: data.status,
  component: data.component,
  audit_passed: result.audit_passed !== false,
  security_issues: result.security_issues || [],
  needs_review: result.security_issues && result.security_issues.length > 0,
  processed_at: data.processed_at
};

// OpenClaw RPA 结果处理
const data = $input.first().json;
const result = data.result || {};

return {
  task_id: data.task_id,
  status: data.status,
  component: data.component,
  screenshot_url: result.screenshot_url || null,
  extracted_text: result.extracted_text || null,
  gui_success: result.success !== false,
  processed_at: data.processed_at
};

// 错误处理: 分诊 + 升级决策
const data = $input.first().json;
const error = data.error || {};
const errorType = error.type || 'unknown';

let action = 'notify';
let escalate = false;

if (errorType === 'timeout') {
  action = 'retry';
} else if (errorType === 'auth_failure') {
  action = 'fix_config';
  escalate = true;
} else if (errorType === 'crash') {
  action = 'restart_service';
  escalate = true;
}

return {
  task_id: data.task_id,
  error_type: errorType,
  action: action,
  escalate: escalate,
  message: error.message || 'Unknown error',
  processed_at: data.processed_at
};
